import{_ as t,o,c as a,a3 as i}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"70. Parental Leave","description":"","frontmatter":{"title":"70. Parental Leave","eba":"Allied Health Professionals 2021-2026","topics":["leave","parental-leave","employment","preliminary"]},"headers":[],"relativePath":"ebas/allied-health/leave/70-parental-leave.md","filePath":"ebas/allied-health/leave/70-parental-leave.md"}'),n={name:"ebas/allied-health/leave/70-parental-leave.md"};function r(l,e,s,p,h,d){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="_70-parental-leave" tabindex="-1">70. Parental Leave <a class="header-anchor" href="#_70-parental-leave" aria-label="Permalink to &quot;70. Parental Leave&quot;">​</a></h1><p>This clause 70 deals with parental leave, including paid parental leave. The issue of superannuation and parental leave (both paid and unpaid) is addressed at subclause 30.6.</p><p><strong>70.1</strong> Structure of clause This clause 70 is structured as follows:</p><p><strong>(a)</strong> Structure of clause: subclause 70.1;</p><p><strong>(b)</strong> Definitions: subclause 70.2;</p><p><strong>(c)</strong> Long parental leave – unpaid: subclause 70.3;</p><p><strong>(d)</strong> Short parental leave – unpaid: subclause 70.4;</p><p><strong>(e)</strong> Hospitalised children – agreement to not take unpaid Parental Leave: subclause 70.5</p><p><strong>(f)</strong> Flexible Parental Leave – unpaid: subclause 70.6;</p><p><strong>(g)</strong> Paid parental leave: subclause 70.7;</p><p><strong>(h)</strong> Notice and evidence requirements: subclause 70.8;</p><p><strong>(i)</strong> Parental leave associated with the birth of a Child – additional provisions: subclause 70.9;</p><p><strong>(j)</strong> Unpaid pre-adoption leave: subclause 70.10;</p><p><strong>(k)</strong> Where placement does not proceed or continue: subclause 70.11;</p><p><strong>(l)</strong> Special maternity leave: subclause 70.12;</p><p><strong>(m)</strong> Variation of period of unpaid parental leave (up to 12 months): subclause 70.13;</p><p><strong>(n)</strong> Right to request extension of period of unpaid parental leave beyond 12 months: subclause 70.14;</p><p><strong>(o)</strong> Parental leave and other entitlements: subclause 70.15;</p><p><strong>(p)</strong> Transfer to a safe job and ionising radiation: subclause 70.16;</p><p><strong>(q)</strong> Returning to work after a period of parental leave: subclause 70.17;</p><p><strong>(r)</strong> Replacement Employees: subclause 70.18;</p><p><strong>(s)</strong> Communication during parental leave – organisational change: subclause 70.19; and</p><p><strong>(t)</strong> Keeping in touch days: subclause 70.20. Other provisions associated with parental leave are also included in this Agreement. Specifically, prenatal leave at <a href="/eba/ebas/allied-health/leave/68-pre-natal-leave.html">clause 68</a>, flexible working arrangements which includes the right to request to return from parental leave on a part-time basis at <a href="/eba/ebas/allied-health/workplace-rights/96-flexible-working-arrangements.html">clause 96</a>, leave to attend interviews and examinations relevant to adoption leave (pre-adoption leave) at <a href="/eba/ebas/allied-health/leave/69-pre-adoption-leave.html">clause 69</a>, breastfeeding at <a href="/eba/ebas/allied-health/leave/71-breastfeeding.html">clause 71</a> and ending employment during parental leave at <a href="/eba/ebas/allied-health/employment/26-ending-employment-during-parental-leave.html">clause 26</a>.</p><p><strong>70.2</strong> Definitions For the purposes of this clause 70:</p><p><strong>(a)</strong> Child means:</p><p><strong>(i)</strong> in relation to birth-related leave, a child (or children from a multiple birth) of the Eligible Employee or the Eligible Employee’s Spouse;</p><p><strong>(ii)</strong> in relation to adoption-related leave, a child (or children) under sixteen 16 (as at the day of placement or expected day of placement) who is placed or who is to be placed with the Eligible Employee for the purposes of adoption, other than a child or step-child of the Eligible Employee or of the Spouse of the Eligible Employee or a child who has previously lived continuously with the Eligible Employee for a period of six (6) months or more (Adopted Child); or</p><p><strong>(iii)</strong> as the case requires, includes a Stillborn Child.</p><p><strong>(b)</strong> Continuous Service includes continuous service with one and the same Employer or continuous service with more than one employer including Institutions or Statutory Bodies (as defined at subclauses 72.2(b) and (h) and includes any period of employment that would count as service under the Act.</p><p><strong>(c)</strong> Eligible Casual Employee means an Employee employed by the Employer in casual employment on a regular and systematic basis for a sequence of periods of employment during a period of at least 12 months and who has, but for the birth or expected birth of a Child or the decision to adopt a Child, a reasonable expectation of continuing engagement by the Employer on a regular and systematic basis.</p><p><strong>(d)</strong> Eligible Employee for the purposes of this clause 70 means an Employee who has at least six (6) months’ Continuous Service or an Eligible Casual Employee as defined above.</p><p><strong>(e)</strong> Employee Couple has the same meaning as under the Act.</p><p><strong>(f)</strong> Flexible Parental Leave means the 30 days’ unpaid parental leave an Eligible Employee may take under subclause 70.6 as part of their 52 weeks&#39; entitlement of Parental Leave.</p><p><strong>(g)</strong> Long Parental Leave means the 52 weeks’ parental leave an Eligible Employee may take under subclause 70.3.</p><p><strong>(h)</strong> Notional Flexible Period is the period during which the Eligible Employee would be on Flexible Parental Leave if the Eligible Employee took leave for all of the Eligible Employee&#39;s notified flexible days in a single continuous period.</p><p><strong>(i)</strong> Short Parental Leave means the up to eight (8) weeks’ concurrent parental leave an Eligible Employee may take under subclause 70.4 (Short Parental Leave – Unpaid).</p><p><strong>(j)</strong> Stillbirth means the delivery of a Stillborn Child (as defined in subclause 4.22).</p><p><strong>70.3</strong> Long Parental Leave – Unpaid</p><p><strong>(a)</strong> An Eligible Employee is entitled to 12 months’ unpaid Long Parental Leave if:</p><p><strong>(i)</strong> the leave is associated with: A. the birth of a Child (including a Stillbirth) of the Eligible Employee or the Eligible Employee’s Spouse; or B. the placement of a Child with the Eligible Employee for adoption; and</p><p><strong>(ii)</strong> the Eligible Employee has or will have a responsibility for the care of the Child, or in the case of a Stillbirth, the Eligible Employee would have had a responsibility for the care of the Child if the Child had been born alive.</p><p><strong>(b)</strong> Except as provided at subclause 70.6 (Flexible Parental Leave - Unpaid) and subclause 70.20 (Keeping in Touch Days), the Eligible Employee must take the leave in a single continuous period.</p><p><strong>(c)</strong> Where an Eligible Employee is a member of an Employee Couple, except as provided at subclauses 70.6 (Flexible Parental leave - Unpaid and 70.4 (Short Parental Leave – Unpaid), parental leave must be taken by only one (1) parent of an Employee Couple at a time in a single continuous period.</p><p><strong>(d)</strong> Each member of an Employee Couple may take a separate period of up to 12 months of Long Parental Leave. The period of Long Parental Leave will be reduced by any period of Short Parental Leave taken by the Eligible Employee.</p><p><strong>(e)</strong> Subject to subclause 70.3(f), an Eligible Employee may be able to extend a period of unpaid parental leave in accordance with subclause 70.13 (Variation of period of unpaid parental leave – up to 12 months).</p><p><strong>(f)</strong> An Eligible Employee’s entitlement to Long Parental Leave (other than Flexible Parental Leave) will end on the first day that the Eligible Employee takes Flexible Parental Leave. This means that if an Eligible Employee intends on taking a period of continuous unpaid parental leave they must do so before they take any Flexible Parental Leave.</p><p><strong>70.4</strong> Short Parental Leave – Unpaid</p><p><strong>(a)</strong> This subclause 70.4 applies to an Eligible Employee who is a member of an Employee Couple.</p><p><strong>(b)</strong> An Eligible Employee who is not at that point taking Long Parental Leave, may take up to eight (8) weeks’ leave concurrently with any parental leave taken by the other member of the Employee Couple. Short Parental Leave may be taken in separate periods but, unless the Employer agrees, each period must not be shorter than two (2) weeks.</p><p><strong>(c)</strong> The period of Short Parental Leave will be deducted from the period of Long Parental Leave to which the Eligible Employee is entitled under subclause 70.3 (if applicable).</p><p><strong>70.5</strong> Hospitalised children – agreement to not take unpaid Parental Leave</p><p><strong>(a)</strong> If:</p><p><strong>(i)</strong> a Child is required to remain in hospital after the Child&#39;s birth, or is hospitalised immediately after the Child&#39;s birth, including because: A. the Child was born prematurely; B. the Child developed a complication or contracted an illness during the child&#39;s period of gestation or at birth; or C. the Child developed a complication or contracted an illness following the Child&#39;s birth; and</p><p><strong>(ii)</strong> an Employee, whether before or after the birth of the Child, gives notice in accordance with subclause 70.8 of the taking of a period of unpaid parental leave (the original leave period) in relation to the Child; then the Employee may agree with their Employer that the Employee will not take unpaid parental leave for a period (the permitted work period) while the Child remains in hospital.</p><p><strong>(b)</strong> If the Employee and Employer so agree, then the following rules have effect:</p><p><strong>(i)</strong> the Employee is taken to not be taking unpaid parental leave during the permitted work period;</p><p><strong>(ii)</strong> the permitted work period does not break the continuity of the original leave period; and</p><p><strong>(iii)</strong> the Employee is taken to have advised the Employer, for the purposes of subclause 70.8(b), of an end date for the original leave period that is the date on which that period would end if it were extended by a period equal to the permitted work period.</p><p><strong>(c)</strong> The permitted work period must start after the birth of the Child.</p><p><strong>(d)</strong> The permitted work period ends at the earliest of the following:</p><p><strong>(i)</strong> the time agreed by the Employer and Employee;</p><p><strong>(ii)</strong> the end of the day of the Child&#39;s first discharge from hospital after birth; or</p><p><strong>(iii)</strong> if the Child dies before being discharged, the end of the day the Child dies.</p><p><strong>(e)</strong> Only one period may be agreed to under subclause 70.5(a) for which the Employee will not take unpaid parental leave in relation to the Child.</p><p><strong>(f)</strong> The Employee must, if required by the Employer, give the Employer evidence (including without limitation, a medical certificate) that would satisfy a reasonable person of either or both of the following:</p><p><strong>(i)</strong> that subclause 70.5(a)(i) applies in relation to the child;</p><p><strong>(ii)</strong> that the Employee is fit for work.</p><p><strong>70.6</strong> Flexible Parental Leave - Unpaid</p><p><strong>(a)</strong> An Eligible Employee may take up to 30 days of their Parental Leave entitlement (Flexible Parental Leave) during the 24-month period starting on the date of birth (including a Stillbirth) or day of placement of the Child if the requirements of this subclause 70.6 are satisfied in relation to the leave.</p><p><strong>(b)</strong> The number of days of Flexible Parental Leave that the Eligible Employee takes must not be more than the number of flexible days notified to the Employer under subclause 70.8(f)(iii) (subject to any agreement under subclause 70.8(f)(iv)).</p><p><strong>(c)</strong> An Eligible Employee must take the Flexible Parental Leave as:</p><p><strong>(i)</strong> a single continuous period of one (1) or more days; or</p><p><strong>(ii)</strong> separate periods of one (1) or more days each.</p><p><strong>(d)</strong> An Eligible Employee may take the Flexible Parental Leave whether or not they have taken unpaid Parental Leave under this clause 70.</p><p><strong>(e)</strong> An Eligible Employee may take Flexible Parental Leave after taking one (1) or more periods of unpaid Parental Leave under this clause 70 only if the total of those periods (disregarding any extension under subclause 70.13 or 70.14) is no longer than 12 months, less the employee&#39;s Notional Flexible Period, provided that the calculation for the Employee’s Notional Flexible Period is based on the assumption that:</p><p><strong>(i)</strong> the Eligible Employee ordinarily works each day that is not a Saturday or Sunday; and</p><p><strong>(ii)</strong> there are no public holidays during the period.</p><p><strong>(f)</strong> A member of an Employee Couple (the first employee) may take Flexible Parental Leave on the same day as the other member of the Employee Couple (the other employee) is taking unpaid Parental Leave only if the total of all periods of unpaid parental leave the first employee takes at the same time as the other employee is no longer than eight (8) weeks.</p><p><strong>70.7</strong> Paid Parental Leave See also subclause 30.6 (Superannuation during parental leave – from 1 July 2022).</p><p><strong>(a)</strong> An Eligible Employee commencing parental leave is entitled to paid parental leave on the following basis from 7 July 2022 onwards:</p><p><strong>(i)</strong> a Primary Carer taking Long Parental Leave will be entitled to fourteen (14) weeks’ paid parental leave or twenty-eight (28) week’s paid parental leave on half pay, provided that the Long Parental Leave is taken contemporaneously with the birth or placement of the Child; and</p><p><strong>(ii)</strong> a non-Primary Carer taking Short Parental Leave will be entitled to two (2) weeks’ paid parental leave; save that an Eligible Employee is not entitled to both paid Long Parental Leave and paid Short Parental Leave in respect of the same birth or adoption. Primary Carer in this subclause 70.7(a) means the person who has responsibility for the care of the Child. Only one (1) person can be the Child&#39;s Primary Carer on a particular day.</p><p><strong>(b)</strong> Subclause 70.7(a) is subject to subclause 70.5, in which case the Employee taking Long or Short Parental Leave may agree with the Employer that the Employee will not take Long or Short Parental Leave during the permitted work period while the Child remains hospitalised.</p><p><strong>(c)</strong> Payment Payment for paid parental leave will be based on the Employee’s ordinary time rate of pay provided in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a> and the higher qualifications allowance (if applicable) and will be based on the following:</p><p><strong>(i)</strong> Full-time Employee – 38 ordinary hours;</p><p><strong>(ii)</strong> Part-time Employee – the Employee’s contracted hours, save that where the part-time Employee’s ordinary hours fluctuate because the Employee works additional ordinary shifts (but excluding a permanent variation) an average of the Employee’s ordinary hours over: A. the preceding 12 months; or B. the Employee’s period of service where the Employee has less than 12 months service; will apply where this is more favourable to the Employee; or</p><p><strong>(iii)</strong> Casual Employee – average of the Employee’s ordinary hours of work over the preceding 12 months; save that, if an Eligible Employee has changed their position or reduced their ordinary hours as a result of the pregnancy or adoption prior to taking the paid parental leave, the above will be calculated using the Employee’s ordinary hours or position prior to the changed arrangement.</p><p><strong>(d)</strong> Paid parental leave is in addition to any relevant Commonwealth Government paid parental leave scheme (subject to the requirements of any applicable legislation).</p><p><strong>(e)</strong> The Employer and Eligible Employee may reach agreement on alternative arrangements as to how the paid parental leave under this Agreement is paid.</p><p>For example, such leave may be paid in smaller amounts over a longer period, consecutively or concurrently with any relevant Commonwealth Government parental leave scheme (subject to the requirements of any applicable legislation) and may include a voluntary contribution to superannuation.</p><p><strong>(f)</strong> Such agreement must be in writing and signed by the parties. The Eligible Employee must nominate a preferred payment arrangement at least four (4) weeks prior to the expected date of birth or date of placement of the Child.</p><p><strong>(g)</strong> In the absence of agreement, such leave will be paid during the ordinary pay periods corresponding with the period of the leave.</p><p><strong>(h)</strong> The paid parental leave prescribed by this subclause 70.7 will be concurrent with any relevant unpaid entitlement prescribed by the NES/this Agreement.</p><p><strong>70.8</strong> Notice and evidence requirements</p><p><strong>(a)</strong> Subject to subclause 70.8(f) (Notice – Flexible Parental Leave - Unpaid), an Eligible Employee must give to the Employer:</p><p><strong>(i)</strong> at least 10 weeks written notice, or if that is not practicable as soon as practicable, of the intention to take parental leave, including the proposed start and end dates; or</p><p><strong>(ii)</strong> if the parental leave is to be taken in separate periods of concurrent leave under subclause 70.4(b) and the leave is not the first of those leave periods of concurrent leave, then only notice of at least four (4) weeks before starting the period of concurrent leave is required, or if that is not practicable give written notice as soon as practicable, save that if the Eligible Employee gave written notice of the separate periods of concurrent leave in the notice provided under subclause 70.8(a)(i), there is no requirement for the Eligible Employee to give notice in accordance with this subclause 70.8(a)(ii).</p><p><strong>(b)</strong> Subject to clause 70.8(f) (Notice – Flexible Parental Leave - Unpaid), at least four (4) weeks before the intended commencement of parental leave, or if that is not practicable as soon as practicable, the Eligible Employee must confirm in writing the intended start and end dates of the parental leave, or advise the Employer of any changes to the notice provided in subclause 70.8(a), unless it is not practicable to do so. This does not apply to a notice for a period of concurrent leave period referred to in subclause 70.8 that already requires four (4) weeks’ notice.</p><p><strong>(c)</strong> Where requested by the Employer, the Eligible Employee will also provide particulars of any period of partner (or like authorised) leave sought.</p><p><strong>(d)</strong> The Employer may require the Eligible Employee to provide evidence which would satisfy a reasonable person of:</p><p><strong>(i)</strong> in the case of birth-related leave: A. the date of birth, or expected date of birth of the Child (including without limitation, a medical certificate or certificate from a registered midwife, stating the date of birth or expected</p><p>date of birth); and B. if relevant, that their Child was stillborn (including without limitation, a certification by a medical practitioner or registered midwife of the child as having been delivered); or</p><p><strong>(ii)</strong> in the case of adoption-related leave, the commencement of the placement (or expected day of placement) of the Child and that the Child will be under 16 years of age as at the day of placement or expected day of placement.</p><p><strong>(e)</strong> An Employee will not be in breach of this subclause 70.8 if failure to give the stipulated notice is occasioned by the birth of the Child or placement occurring earlier than the expected date or in other unexpected circumstances. In these circumstances the notice and evidence requirements of this subclause 70.8 should be provided as soon as reasonably practicable.</p><p><strong>(f)</strong> Notice requirements - Flexible Parental Leave - Unpaid</p><p><strong>(i)</strong> If an Employee wishes to take unpaid Flexible Parental Leave, the Employee must give notice to the Employer as follows: A. where the Employee also takes unpaid Long Parental Leave or Short Parental Leave under subclauses 70.3 or 70.4 (the original leave); i. at the same time as the Employee gives notice in accordance with subclause 70.8(a) in relation to the original leave, unless subclause 70.8(f)(i)A.ii below applies; or ii. if the Employee takes more than one period of unpaid Short Parental Leave, at the same time as the Employee gives notice in accordance with subclause 70.8(a) in relation to the first of those periods of leave; or B. otherwise - at least 10 weeks before starting the Flexible Parental Leave.</p><p><strong>(ii)</strong> If the Employer agrees, the notice may be given at a later time than that specified in subclause 70.8(f)(i).</p><p><strong>(iii)</strong> The notice under subclause 70.8(f)(i) must specify the total number of days (Flexible Days) of Flexible Parental Leave that the Employee intends to take in relation to the Child.</p><p><strong>(iv)</strong> If the Employer agrees, the Employee may: A. reduce the number of flexible days, including by reducing the number of flexible days to zero; or B. increase the number of flexible days, but not so as to increase the number of flexible days above 30.</p><p><strong>(v)</strong> The Employee must give the Employer written notice of a flexible day on which the Employee will take Flexible Parental Leave: A. at least four (4) weeks before that day; or B. if that is not practicable, as soon as practicable (which may be a time after the leave has started).</p><p><strong>(vi)</strong> If the Employer agrees, the Employee may change a day on which the Employee takes Flexible Parental Leave from a day specified in a notice under subsection 70.8(f)(v).</p><p><strong>70.9</strong> Parental leave associated with the birth of a Child – additional provisions</p><p><strong>(a)</strong> Subject to the limits on duration of parental leave set out in this Agreement and unless agreed otherwise between the Employer and Eligible Employee, an Eligible Employee who is pregnant may commence Long Parental Leave at any time up to six (6) weeks immediately prior to the expected date of birth.</p><p><strong>(b)</strong> Six weeks before the birth</p><p><strong>(i)</strong> Where a pregnant Eligible Employee continues to work during the six (6) week period immediately prior to the expected date of birth, the Employer may require the Eligible Employee to provide a medical certificate stating that they are fit for work and, if so, whether it is inadvisable for them to continue in their present position because of illness or risks arising out of the Eligible Employee’s pregnancy or hazards connected with the position.</p><p><strong>(ii)</strong> Where a request is made under subclause 70.9(b)(i) and an Eligible Employee: A. does not provide the Employer with the requested certificate within seven (7) days of the request; or B. within seven (7) days after the request gives the Employer a medical certificate stating that the Eligible Employee is not fit for work;</p><p><strong>(iii)</strong> the Employer may require the Eligible Employee to commence their parental leave as soon as practicable.</p><p><strong>(iv)</strong> Where a request is made under subclause 70.9(b)(i) and an Eligible Employee provides a medical certificate that states that the Eligible Employee is fit for work but it is inadvisable for the Eligible Employee to continue in their present position during a stated period, subclause 70.16 (Transfer to a safe job) will apply.</p><p><strong>70.10</strong> Pre-adoption leave Employees’ entitlement to pre-adoption leave is set out at <a href="/eba/ebas/allied-health/leave/69-pre-adoption-leave.html">clause 69</a> (Pre- adoption leave).</p><p><strong>70.11</strong> Where placement does not proceed or continue</p><p><strong>(a)</strong> Where the placement of the Child for adoption with an Eligible Employee does not proceed or continue, the Eligible Employee will notify the Employer immediately.</p><p><strong>(b)</strong> Where the Eligible Employee had, at the time, started a period of adoption-related leave in relation to the placement, the Eligible Employee’s entitlement to adoption-related leave is not affected, except where the Employer gives written notice under subclause 70.11(c).</p><p><strong>(c)</strong> The Employer may give the Eligible Employee written notice that, from a stated day no earlier than four (4) weeks after the day the notice is given, any untaken long adoption-related leave is cancelled with effect from that day.</p><p><strong>(d)</strong> Where the Eligible Employee wishes to return to work due to a placement not proceeding or continuing, the Employer must nominate a time not exceeding four (4) weeks from receipt of notification for the Eligible Employee’s return to work.</p><p><strong>70.12</strong> Special maternity leave</p><p><strong>(a)</strong> Entitlement to unpaid special birth-related leave</p><p><strong>(i)</strong> An Eligible Employee is entitled to a period of unpaid special leave if they are not fit for work during that period because: A. they have a pregnancy-related illness affecting them; or B. all of the following apply: i. they have been pregnant; and ii. the pregnancy ends after a period of gestation of at least 12 weeks otherwise than by the birth of a living Child; and iii. the birth is not a Stillbirth.</p><p><strong>(ii)</strong> An Eligible Employee who has an entitlement to personal leave may, in this subclause 70.12(a).</p><p><strong>(iii)</strong> Where the pregnancy ends more than 28 weeks from the expected date of birth of the Child, the Eligible Employee is entitled to access any paid and/or unpaid personal leave entitlements in accordance with the relevant personal leave provisions.</p><p><strong>(b)</strong> Entitlement to paid special birth-related leave</p><p><strong>(i)</strong> An Eligible Employee is entitled to a period of paid special leave if their pregnancy terminates at or after the completion of 20 weeks’ gestation or the Eligible Employee gives birth but the baby subsequently dies.</p><p><strong>(ii)</strong> Paid special leave is paid leave up to the amount of paid leave available under subclause 70.7(a)(i) (plus superannuation) based on the amount of leave taken, in circumstances where the Employee intended to take long parental leave at the time of birth or placement.</p><p>Examples:</p><ol><li>An Employee who takes six (6) weeks paid special leave will be paid six (6) weeks.</li><li>An Employee who takes 16 weeks will be paid the full amount of paid leave available under subclause 70.7(a)(i) (14 weeks).</li></ol><p><strong>(iii)</strong> Paid special leave is in addition to any unpaid special leave taken under subclause 70.12(a)(i).</p><p><strong>(iv)</strong> Paid leave available under subclause 70.7(a)(ii) will also apply in these circumstances.</p><p><strong>(c)</strong> Evidence If an Eligible Employee takes leave under this subclause 70.12 the Employer may require the Eligible Employee to provide evidence that would satisfy a reasonable person of the matters referred to in subclause 70.12(a)(i) or 70.12(b)(i) or to provide a certificate from a registered medical practitioner. The Eligible Employee must give notice to the Employer as soon as practicable, advising the Employer of the period or the expected period of the leave under this provision.</p><p><strong>70.13</strong> Variation of period of unpaid parental leave (up to 12 months)</p><p><strong>(a)</strong> Where an Eligible Employee has:</p><p><strong>(i)</strong> given notice of the taking of a period of Long Parental Leave under subclause 70.3;</p><p><strong>(ii)</strong> the length of this period of Long Parental Leave as notified to the Employer is less than the Eligible Employee’s available entitlement to Long Parental Leave;</p><p><strong>(iii)</strong> commenced the period of Long Parental Leave; and</p><p><strong>(iv)</strong> not taken a period of Flexible Parental Leave – Unpaid; the Eligible Employee may change the period of parental leave on one occasion. Any change is to be notified (including the new end date for the leave) as soon as possible but no less than four (4) weeks prior to the commencement of the changed arrangements. Nothing in this subclause 70.13 detracts from the basic entitlement in subclause 70.3 (Long Parental Leave – Unpaid) or subclause</p><p><strong>70.14</strong> (Right to request an extension of period of unpaid parental leave beyond 12 months).</p><p><strong>(b)</strong> If the Employer and Eligible Employee agree, the Eligible Employee may further change the period of parental leave.</p><p><strong>70.14</strong> Right to request an extension of period of unpaid parental leave beyond 12 months</p><p><strong>(a)</strong> An Eligible Employee entitled to Long Parental Leave pursuant to the provisions of subclause 70.3 may request the Employer to allow the Eligible Employee to extend the period of Long Parental Leave by a further continuous period of up to 12 months immediately following the end of the available parental leave.</p><p><strong>(b)</strong> Request to be in writing</p><p>The request must be in writing and must be given to the Employer at least four (4) weeks before the end of the available parental leave period.</p><p><strong>(c)</strong> Response to be in writing The Employer must give the Eligible Employee a written response to the request stating whether the Employer grants or refuses the request. The response must be given as soon as practicable, and not later than 21 days, after the request is made.</p><p><strong>(d)</strong> Refusal only on reasonable business grounds The Employer may only refuse the request on reasonable business grounds.</p><p><strong>(e)</strong> Reasons for refusal to be specified If the Employer refuses the request, the written response must include details of the reasons for the refusal.</p><p><strong>(f)</strong> Reasonable opportunity to discuss The Employer must not refuse the request unless the Employer has given the Eligible Employee a reasonable opportunity to discuss the request.</p><p><strong>(g)</strong> Employee Couples Where a member of an Employee Couple is requesting an extension to a period of Long Parental Leave in relation to a Child:</p><p><strong>(i)</strong> the request must specify: A. any amount of Long Parental Leave that the other member of the Employee Couple has taken, or will have taken in relation to the Child before the extension starts; B. if the other member of the Employee Couple has given notice of an intention to take Flexible Parental Leave - Unpaid (in accordance with subclause 70.8(f), the request must specify the number of flexible days that will not have been taken when the period of extended leave commences;</p><p><strong>(ii)</strong> the period of extension cannot exceed 12 months, less any period: A. of Long Parental Leave (other than Flexible Parental Leave - Unpaid) that the other member of the Employee Couple has taken, or will have taken, in relation to the Child before the extension starts; and B. equal to the other member’s Notional Flexible Period (if subclause 70.14(g)(i)B. applies above); and</p><p><strong>(iii)</strong> the amount of Long Parental Leave to which the other member of the Employee Couple is entitled under subclause 70.3 in relation to the Child is reduced by the period of the extension.</p><p><strong>(h)</strong> No extension beyond 24 months An Eligible Employee is not entitled to extend the period of Long Parental Leave beyond 24 months after the date of birth or day of placement of the Child.</p><p><strong>70.15</strong> Parental leave and other entitlements An Eligible Employee may use any accrued annual leave or long service leave entitlements concurrently with Parental Leave, save that taking that leave does not have the effect of extending the period of Parental Leave. If the Employee does so, the taking of that other paid leave does not break the continuity of the period of unpaid parental leave.</p><p><strong>70.16</strong> Transfer to a safe job and Ionising Radiation</p><p><strong>(a)</strong> Where an Employee is pregnant and provides evidence that would satisfy a reasonable person that they are fit for work but it is inadvisable for the Employee to continue in their present position for a stated period (the risk period) because of:</p><p><strong>(i)</strong> illness or risks arising out of the pregnancy; or</p><p><strong>(ii)</strong> hazards connected with the position; the Employee must be transferred to an appropriate safe job if one is available for the risk period, with no other change to the Employee’s terms and conditions of employment.</p><p><strong>(b)</strong> Paid no safe job leave If:</p><p><strong>(i)</strong> subclause 70.16(a) applies to a pregnant Eligible Employee but there is no appropriate safe job available;</p><p><strong>(ii)</strong> the Eligible Employee is entitled to Long Parental Leave; and</p><p><strong>(iii)</strong> the Eligible Employee has complied with the notice of intended start and end dates of leave and evidence requirements under subclause 70.8 for taking Long Parental Leave; then the Eligible Employee is entitled to paid no safe job leave for the risk period.</p><p><strong>(c)</strong> If the Eligible Employee takes paid no safe job leave for the risk period, the Employer must pay the Eligible Employee at the Eligible Employee’s ordinary hours rate of pay for the Eligible Employee&#39;s ordinary hours of work in the risk period.</p><p><strong>(d)</strong> This entitlement to paid no safe job leave is in addition to any other leave entitlement the Eligible Employee may have.</p><p><strong>(e)</strong> If an Eligible Employee, during the six (6) week period before the expected date of birth, is on paid no safe job leave, the Employer may request that the Eligible Employee provide a medical certificate within seven (7) days stating whether the Eligible Employee is fit for work.</p><p><strong>(f)</strong> If the Eligible Employee has either:</p><p><strong>(i)</strong> not complied with the request from the Employer; or</p><p><strong>(ii)</strong> provided a medical certificate stating that they are not fit for work;</p><p>then the Eligible Employee is not entitled to paid no safe job leave and the Employer may require the Eligible Employee to take parental leave as soon as practicable.</p><p><strong>(g)</strong> Unpaid no safe job leave If:</p><p><strong>(i)</strong> subclause 70.16(a) applies to a pregnant Employee but there is no appropriate safe job available;</p><p><strong>(ii)</strong> the Employee will not be entitled to Long Parental Leave as at the expected date of birth; and</p><p><strong>(iii)</strong> the Employee has given the Employer evidence that would satisfy a reasonable person of the pregnancy if required by the Employer (which may include a requirement to provide a medical certificate); then the Employee is entitled to unpaid no safe job leave for the risk period.</p><p><strong>(h)</strong> Ionising Radiation This subclause 70.16(h) does not diminish any prescribed safety standard.</p><p><strong>(i)</strong> Where an Employee is pregnant and their role includes duties that expose them to ionising radiation, at any time during the pregnancy the Employee may request a temporary modification to those duties or other mitigation (for example, additional protection) to avoid exposure to ionising radiation, including where the level of exposure is within the relevant safe exposure standard.</p><p><strong>(ii)</strong> The Employer will: A. consider whether it can accommodate a temporary modification to avoid exposing the Employee to ionising radiation and will accommodate the request where it can reasonably do so; and B. meet with the Employee to discuss the request and options to accommodate that request or alternative.</p><p><strong>(iii)</strong> In the event of a dispute, <a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a> of this Agreement applies.</p><p><strong>(iv)</strong> The Union or other representative may represent the Employee at any time, including the meeting referred to at subclause 70.16(h)(ii)B above.</p><p><strong>70.17</strong> Returning to work after a period of parental leave</p><p><strong>(a)</strong> An Eligible Employee will endeavour to notify the Employer of their intention to return to work after a period of Long Parental Leave at least four (4) weeks prior to the end of the leave, or where that is not practicable, as soon as practicable.</p><p><strong>(b)</strong> An Eligible Employee will be entitled to return:</p><p><strong>(i)</strong> unless subclause 70.17(b)(ii) or subclause 70.17(b)(iii) applies, to the position which they held immediately before proceeding on parental leave;</p><p><strong>(ii)</strong> if the Eligible Employee was promoted or voluntarily transferred to a new position (other than to a safe job pursuant to subclause 70.16), to the new position;</p><p><strong>(iii)</strong> if subclause 70.17(b)(ii) does not apply, and the Eligible Employee began working part-time because of the pregnancy of the Eligible Employee, or their Spouse, to the position held immediately before starting to work part- time.</p><p><strong>(c)</strong> Subclause 70.17(b) is not to result in the Eligible Employee being returned to the safe job to which the Eligible Employee was transferred under subclause 70.16. In such circumstances, the Eligible Employee will be entitled to return to the position held immediately before the transfer.</p><p><strong>(d)</strong> Where the relevant former position (per subclauses 70.17(b) and 70.17(c) above) no longer exists, an Eligible Employee is entitled to return to an available position for which the Eligible Employee is qualified and suited nearest in status and pay to that of their pre-parental leave position.</p><p><strong>(e)</strong> The Employer must not fail to re-engage an Eligible Employee because:</p><p><strong>(i)</strong> the Eligible Employee or Eligible Employee’s Spouse is pregnant; or</p><p><strong>(ii)</strong> the Eligible Employee is or has been immediately absent on parental leave.</p><p><strong>(f)</strong> The rights of the Employer in relation to engagement and re-engagement of casual Employees are not affected, other than in accordance with this clause 70.</p><p><strong>(g)</strong> Stillbirth or death of child – cancelling leave or returning to work</p><p><strong>(i)</strong> In the event of a Stillbirth, or if a Child dies during the 24-month period starting on the child&#39;s date of birth, then an Eligible Employee who is entitled to a period of parental leave in relation to the Child may: A. before the period of leave starts, give their Employer written notice cancelling the leave; or B. if the period of leave has started, give their Employer written notice that the Employee wishes to return to work on a specified day (which must be at least four (4) weeks after the date on which the Employer receives the notice).</p><p><strong>(ii)</strong> Where notice under subclause 70.17(g)(i) is given, the Employee&#39;s entitlement to Parental Leave in relation to the Child ends: A. if the action is taken under subclause 70.17(g)(i)A, immediately after the cancellation of the leave; or B. if the action is taken under subclause 70.17(g)(i)B, immediately before the specified day.</p><p><strong>(iii)</strong> This subclause 70.17(g) does not limit subclause 70.13(b) (dealing with the Employee varying the period of unpaid parental leave with the agreement of the Employer).</p><p><strong>(h)</strong> Employee who ceases to have responsibility for care of Child</p><p><strong>(i)</strong> This subclause 70.17(h) applies to an Employee who has taken unpaid Parental Leave in relation to a Child if the Employee ceases to have any responsibility for the care of the Child for a reason other than because: A. of a Stillbirth; or B. the Child dies during the 24-month period starting on the child&#39;s date of birth.</p><p><strong>(ii)</strong> The Employer may give the Employee written notice requiring the Employee to return to work on a specified day.</p><p><strong>(iii)</strong> The specified day: A. must be at least four (4) weeks after the notice is given to the Employee; and B. if the leave is birth-related leave taken by an Employee who has given birth, must not be earlier than six (6) weeks after the date of birth of the Child.</p><p><strong>(iv)</strong> The Employee&#39;s entitlement to Parental Leave in relation to the Child ends immediately before the specified day.</p><p><strong>70.18</strong> Replacement Employees</p><p><strong>(a)</strong> A replacement Employee is an Employee specifically engaged or temporarily promoted or transferred, as a result of an Eligible Employee proceeding on parental leave.</p><p><strong>(b)</strong> Before the Employer engages a replacement Employee, the Employer must inform that person of the temporary nature of the employment and of the rights of the Eligible Employee who is being replaced to return to their pre-parental leave position.</p><p><strong>70.19</strong> Communication during parental leave – organisational change</p><p><strong>(a)</strong> Where an Eligible Employee is on parental leave and the Employer proposes a change or makes a decision that will have a significant effect within the meaning of <a href="/eba/ebas/allied-health/consultation-disputes/13-consultation.html">clause 13</a> (Consultation) of this Agreement on the Eligible Employee’s pre- parental leave position and/or on the status, pay or location of the Eligible Employee’s pre-parental leave position, the Employer will comply with the requirements of <a href="/eba/ebas/allied-health/consultation-disputes/13-consultation.html">clause 13</a> (Consultation) which include but are not limited to providing:</p><p><strong>(i)</strong> information in accordance with subclause 13.4; and</p><p><strong>(ii)</strong> an opportunity for discussions with the Eligible Employee and, where relevant, the Eligible Employee’s representative in accordance with subclause 13.6.</p><p><strong>(b)</strong> The Eligible Employee will endeavour to take reasonable steps to inform the Employer about any significant matter that arises whilst the Eligible Employee is taking parental leave that will affect the Eligible Employee’s decision regarding the duration of parental leave to be taken, whether the Eligible Employee intends</p><p>to return to work and whether the Eligible Employee intends to request to return to work on a part-time basis.</p><p><strong>(c)</strong> The Eligible Employee will also notify the Employer of changes of address or other contact details which might affect the Employer’s capacity to comply with subclause 70.19.</p><p><strong>(d)</strong> The Eligible Employee’s pre-parental leave position is:</p><p><strong>(i)</strong> unless subclause 70.19(d)(ii) below applies, the position the Eligible Employee held before starting parental leave;</p><p><strong>(ii)</strong> if, before starting parental leave, the Eligible Employee: A. was transferred to a safe job because of their pregnancy; or B. reduced their working hours due to their pregnancy; the position the Eligible Employee held immediately before that transfer or reduction.</p><p><strong>70.20</strong> Keeping in touch days</p><p><strong>(a)</strong> This clause 70 does not prevent an Eligible Employee from performing work for the Employer on a keeping in touch day while the Eligible Employee is taking Parental Leave. If the Eligible Employee does so, the performance of that work does not break the continuity of the period of Parental Leave.</p><p><strong>(b)</strong> Any day or part of a day on which the Eligible Employee performs work for the Employer during the period of leave is a keeping in touch day if:</p><p><strong>(i)</strong> the purpose of performing the work is to enable the Eligible Employee to keep in touch with their employment in order to facilitate a return to that employment after the end of the period of leave;</p><p><strong>(ii)</strong> both the Eligible Employee and Employer consent to the Eligible Employee performing work for the Employer on that day;</p><p><strong>(iii)</strong> the day is not within: A. if the Eligible Employee suggested or requested that they perform work for the Employer on that day – 14 days after the date of birth, or day of placement, of the Child to which the period of leave relates; or B. otherwise – 42 days after the date of birth, or day of placement, of the Child; and</p><p><strong>(iv)</strong> the Eligible Employee has not already performed work for the Employer or another entity on ten days during the period of leave that were keeping in touch days, subject to subclause 70.20(e)(ii).</p><p><strong>(c)</strong> The duration of the work the Eligible Employee performs on that day is not relevant for the purposes of this subclause 70.20(b).</p><p><strong>(d)</strong> The Employer must not exert undue influence or undue pressure on an Eligible Employee to consent to a keeping in touch day.</p><p><strong>(e)</strong> For the purposes of subclause 70.20(b)(iv) the following will be treated as two (2) separate periods of unpaid parental leave (meaning that an Eligible Employee can work up to ten (10) keeping in touch days during each period of leave):</p><p><strong>(i)</strong> a period of Long Parental Leave taken during the Eligible Employee’s available parental leave period under subclause 70.3 (Long Parental Leave – Unpaid) and 70.13 (Variation of period of unpaid parental leave (up to 12 months)); and</p><p><strong>(ii)</strong> an extension of the period of Long Parental Leave under subclause 70.14 (Right to request an extension of period of unpaid parental leave beyond 12 months).</p><p><strong>(f)</strong> Subclause 70.20(a) does not apply in relation to the Eligible Employee on and after the first day on which the Employee takes flexible unpaid parental leave in relation to the Child.</p><p>Plain language terms: maternity, paternity, baby leave.</p>',231)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
